func (vuo *VisitUpdateOne) sqlSave(ctx context.Context) (_node *Visit, err error) {
	_spec := sqlgraph.NewUpdateSpec(visit.Table, visit.Columns, sqlgraph.NewFieldSpec(visit.FieldID, field.TypeInt64))
	id, ok := vuo.mutation.ID()
	if !ok {
		return nil, &ValidationError{Name: "id", err: errors.New(`ent: missing "Visit.id" for update`)}
	}
	_spec.Node.ID.Value = id
	if fields := vuo.fields; len(fields) > 0 {
		_spec.Node.Columns = make([]string, 0, len(fields))
		_spec.Node.Columns = append(_spec.Node.Columns, visit.FieldID)
		for _, f := range fields {
			if !visit.ValidColumn(f) {
				return nil, &ValidationError{Name: f, err: fmt.Errorf("ent: invalid field %q for query", f)}
			}
			if f != visit.FieldID {
				_spec.Node.Columns = append(_spec.Node.Columns, f)
			}
		}
	}
	if ps := vuo.mutation.predicates; len(ps) > 0 {
		_spec.Predicate = func(selector *sql.Selector) {
			for i := range ps {
				ps[i](selector)
			}
		}
	}
	if value, ok := vuo.mutation.UpdatedAt(); ok {
		_spec.SetField(visit.FieldUpdatedAt, field.TypeTime, value)
	}
	if value, ok := vuo.mutation.RoutePointID(); ok {
		_spec.SetField(visit.FieldRoutePointID, field.TypeInt64, value)
	}
	if value, ok := vuo.mutation.AddedRoutePointID(); ok {
		_spec.AddField(visit.FieldRoutePointID, field.TypeInt64, value)
	}
	if value, ok := vuo.mutation.AgentID(); ok {
		_spec.SetField(visit.FieldAgentID, field.TypeInt64, value)
	}
	if value, ok := vuo.mutation.AddedAgentID(); ok {
		_spec.AddField(visit.FieldAgentID, field.TypeInt64, value)
	}
	if value, ok := vuo.mutation.CheckinLat(); ok {
		_spec.SetField(visit.FieldCheckinLat, field.TypeFloat64, value)
	}
	if value, ok := vuo.mutation.AddedCheckinLat(); ok {
		_spec.AddField(visit.FieldCheckinLat, field.TypeFloat64, value)
	}
	if value, ok := vuo.mutation.CheckinLon(); ok {
		_spec.SetField(visit.FieldCheckinLon, field.TypeFloat64, value)
	}
	if value, ok := vuo.mutation.AddedCheckinLon(); ok {
		_spec.AddField(visit.FieldCheckinLon, field.TypeFloat64, value)
	}
	if value, ok := vuo.mutation.CheckinAt(); ok {
		_spec.SetField(visit.FieldCheckinAt, field.TypeTime, value)
	}
	if value, ok := vuo.mutation.CheckoutLat(); ok {
		_spec.SetField(visit.FieldCheckoutLat, field.TypeFloat64, value)
	}
	if value, ok := vuo.mutation.AddedCheckoutLat(); ok {
		_spec.AddField(visit.FieldCheckoutLat, field.TypeFloat64, value)
	}
	if vuo.mutation.CheckoutLatCleared() {
		_spec.ClearField(visit.FieldCheckoutLat, field.TypeFloat64)
	}
	if value, ok := vuo.mutation.CheckoutLon(); ok {
		_spec.SetField(visit.FieldCheckoutLon, field.TypeFloat64, value)
	}
	if value, ok := vuo.mutation.AddedCheckoutLon(); ok {
		_spec.AddField(visit.FieldCheckoutLon, field.TypeFloat64, value)
	}
	if vuo.mutation.CheckoutLonCleared() {
		_spec.ClearField(visit.FieldCheckoutLon, field.TypeFloat64)
	}
	if value, ok := vuo.mutation.CheckoutAt(); ok {
		_spec.SetField(visit.FieldCheckoutAt, field.TypeTime, value)
	}
	if vuo.mutation.CheckoutAtCleared() {
		_spec.ClearField(visit.FieldCheckoutAt, field.TypeTime)
	}
	if value, ok := vuo.mutation.DurationSeconds(); ok {
		_spec.SetField(visit.FieldDurationSeconds, field.TypeInt64, value)
	}
	if value, ok := vuo.mutation.AddedDurationSeconds(); ok {
		_spec.AddField(visit.FieldDurationSeconds, field.TypeInt64, value)
	}
	if vuo.mutation.DurationSecondsCleared() {
		_spec.ClearField(visit.FieldDurationSeconds, field.TypeInt64)
	}
	if vuo.mutation.PhotosCleared() {
		edge := &sqlgraph.EdgeSpec{
			Rel:     sqlgraph.O2M,
			Inverse: false,
			Table:   visit.PhotosTable,
			Columns: []string{visit.PhotosColumn},
			Bidi:    false,
			Target: &sqlgraph.EdgeTarget{
				IDSpec: sqlgraph.NewFieldSpec(visitphoto.FieldID, field.TypeInt64),
			},
		}
		_spec.Edges.Clear = append(_spec.Edges.Clear, edge)
	}
	if nodes := vuo.mutation.RemovedPhotosIDs(); len(nodes) > 0 && !vuo.mutation.PhotosCleared() {
		edge := &sqlgraph.EdgeSpec{
			Rel:     sqlgraph.O2M,
			Inverse: false,
			Table:   visit.PhotosTable,
			Columns: []string{visit.PhotosColumn},
			Bidi:    false,
			Target: &sqlgraph.EdgeTarget{
				IDSpec: sqlgraph.NewFieldSpec(visitphoto.FieldID, field.TypeInt64),
			},
		}
		for _, k := range nodes {
			edge.Target.Nodes = append(edge.Target.Nodes, k)
		}
		_spec.Edges.Clear = append(_spec.Edges.Clear, edge)
	}
	if nodes := vuo.mutation.PhotosIDs(); len(nodes) > 0 {
		edge := &sqlgraph.EdgeSpec{
			Rel:     sqlgraph.O2M,
			Inverse: false,
			Table:   visit.PhotosTable,
			Columns: []string{visit.PhotosColumn},
			Bidi:    false,
			Target: &sqlgraph.EdgeTarget{
				IDSpec: sqlgraph.NewFieldSpec(visitphoto.FieldID, field.TypeInt64),
			},
		}
		for _, k := range nodes {
			edge.Target.Nodes = append(edge.Target.Nodes, k)
		}
		_spec.Edges.Add = append(_spec.Edges.Add, edge)
	}
	_spec.AddModifiers(vuo.modifiers...)
	_node = &Visit{config: vuo.config}
	_spec.Assign = _node.assignValues
	_spec.ScanValues = _node.scanValues
	if err = sqlgraph.UpdateNode(ctx, vuo.driver, _spec); err != nil {
		if _, ok := err.(*sqlgraph.NotFoundError); ok {
			err = &NotFoundError{visit.Label}
		} else if sqlgraph.IsConstraintError(err) {
			err = &ConstraintError{msg: err.Error(), wrap: err}
		}
		return nil, err
	}
	vuo.mutation.done = true
	return _node, nil
}
